import { describe, expect, it } from 'vitest';
import { generateGoldenSpiralCity } from '@a0n/aeon-3d/worldsim-city-graph';
import {
  encodeCityGraphRecord,
  packCityKnot,
} from '@a0n/aeon-3d/worldsim-city-knot';
import {
  THOTH_PLACE_TOOL_DEFINITIONS,
  THOTH_PLACE_LOAD_TOOL,
  THOTH_PLACE_SAMPLE_TOOL,
  THOTH_PLACE_SIMULATE_TOOL,
  THOTH_PLACE_RECOMMEND_TOOL,
  THOTH_PLACE_QUERY_TOOL,
  THOTH_PLACE_ROUTE_TOOL,
  createThothPlaceMcpClient,
} from '../src/thoth-place-tools';
import { createThothPlaceSimHost } from '../src/thoth-place-sim';

const WINTERS = { name: 'Winters', lat: 38.5249, lon: -121.9708 };

function buildKnot(): Uint8Array {
  return packCityKnot([
    {
      name: WINTERS.name,
      record: encodeCityGraphRecord(
        generateGoldenSpiralCity({ x: 0, y: 0, z: 0 }, 1.2, WINTERS.name, {
          sprawl: 1,
          depthCap: 2,
        } as never)
      ),
    },
  ]);
}

function makeFetch(opts: { noPoi?: boolean } = {}) {
  const knot = buildKnot();
  return (async (url: string) => {
    if (url.includes('city-graphs.knot')) {
      const buf = knot.buffer.slice(
        knot.byteOffset,
        knot.byteOffset + knot.byteLength
      );
      return {
        ok: true,
        status: 200,
        arrayBuffer: async () => buf,
        json: async () => ({}),
      };
    }
    if (url.includes('/api/osm/poi')) {
      if (opts.noPoi) {
        return {
          ok: true,
          status: 200,
          arrayBuffer: async () => new ArrayBuffer(0),
          json: async () => ({ elements: [] }),
        };
      }
      return {
        ok: true,
        status: 200,
        arrayBuffer: async () => new ArrayBuffer(0),
        json: async () => ({
          elements: [
            {
              type: 'node',
              id: 1,
              lat: WINTERS.lat,
              lon: WINTERS.lon,
              tags: { name: 'Luna Cafe', amenity: 'cafe' },
            },
            {
              type: 'node',
              id: 2,
              lat: WINTERS.lat + 0.001,
              lon: WINTERS.lon,
              tags: { name: 'Valley Diner', amenity: 'restaurant' },
            },
            {
              type: 'node',
              id: 3,
              lat: WINTERS.lat,
              lon: WINTERS.lon + 0.001,
              tags: { name: 'Main St Books', shop: 'books' },
            },
          ],
        }),
      };
    }
    return {
      ok: false,
      status: 404,
      arrayBuffer: async () => new ArrayBuffer(0),
      json: async () => ({}),
    };
  }) as unknown as typeof fetch;
}

function makeClient(opts: { observer?: boolean; noPoi?: boolean } = {}) {
  const host = createThothPlaceSimHost({ fetchImpl: makeFetch(opts) });
  return createThothPlaceMcpClient({
    host,
    observer: opts.observer
      ? { lat: WINTERS.lat, lon: WINTERS.lon, cityName: 'Winters' }
      : null,
    now: () => 1_000,
    randomId: (p) => `${p}_fixed`,
  });
}

describe('thoth-place-tools: definitions', () => {
  it('exposes six well-formed tool schemas', async () => {
    expect(THOTH_PLACE_TOOL_DEFINITIONS).toHaveLength(6);
    for (const def of THOTH_PLACE_TOOL_DEFINITIONS) {
      expect(def.type).toBe('function');
      expect(def.function.name).toMatch(/^thoth\/place\./);
      expect(def.function.parameters?.type).toBe('object');
      expect(def.source).toBe('provided');
    }
    const names = THOTH_PLACE_TOOL_DEFINITIONS.map((d) => d.function.name);
    expect(names).toEqual([
      THOTH_PLACE_LOAD_TOOL,
      THOTH_PLACE_SAMPLE_TOOL,
      THOTH_PLACE_SIMULATE_TOOL,
      THOTH_PLACE_RECOMMEND_TOOL,
      THOTH_PLACE_ROUTE_TOOL,
      THOTH_PLACE_QUERY_TOOL,
    ]);
    const client = makeClient();
    expect(await client.listTools()).toHaveLength(6);
    const pre = await client.preflight();
    expect(pre.sessionId).toBe('thoth-place-local');
  });
});

describe('thoth-place-tools: executor', () => {
  it('place.load by city returns a compact summary string', async () => {
    const client = makeClient();
    const res = await client.callTool(THOTH_PLACE_LOAD_TOOL, {
      city: 'Winters',
    });
    expect(res.success).toBe(true);
    const text = res.result as string;
    expect(text).toContain('loaded Winters (pop 7214, catalog-knot)');
    expect(text).toContain('named venues');
    expect(text).toContain('thoth/place.sample');
    expect(text.split('\n').length).toBeLessThanOrEqual(12);
    expect(text.length).toBeLessThan(900);
  });

  it('sample/recommend/query auto-load from the request observer', async () => {
    const client = makeClient({ observer: true });
    const sample = await client.callTool(THOTH_PLACE_SAMPLE_TOOL, { hour: 13 });
    expect(sample.success).toBe(true);
    expect(sample.result as string).toContain('Winters @ 13:00');
    expect(sample.result as string).toContain('simulated residents');

    const rec = await client.callTool(THOTH_PLACE_RECOMMEND_TOOL, {
      kind: 'eat',
      hour: 12.5,
    });
    const recText = rec.result as string;
    expect(recText).toContain('eat in Winters @ 12:30:');
    expect(recText).toMatch(/1\. (Luna Cafe|Valley Diner) \(food/);
    expect(recText).toContain('non-authoritative');

    const q = await client.callTool(THOTH_PLACE_QUERY_TOOL, {
      category: 'shop',
    });
    expect(q.result as string).toContain('Main St Books (shop');
  });

  it('place.simulate aggregates an 8pm-9pm window and a 7-day week', async () => {
    const client = makeClient({ observer: true });
    const evening = await client.callTool(THOTH_PLACE_SIMULATE_TOOL, {
      fromHour: 20,
      toHour: 21,
    });
    const evText = evening.result as string;
    expect(evText).toContain('simulated 20:00–21:00 × 1 day');
    expect(evText).toContain('activity person-hours:');
    expect(evText.length).toBeLessThan(900);

    const week = await client.callTool(THOTH_PLACE_SIMULATE_TOOL, { days: 7 });
    const wkText = week.result as string;
    expect(wkText).toContain('× 7 days');
    expect(wkText).toContain('per-day: busiest');
    expect(wkText.split('\n').length).toBeLessThanOrEqual(12);
  });

  it('degrades honestly: no observer + no load, unknown city, zero venues', async () => {
    const bare = makeClient();
    const res = await bare.callTool(THOTH_PLACE_SAMPLE_TOOL, {});
    expect(res.success).toBe(true);
    expect(res.result as string).toContain('no city sense available');
    expect(res.result as string).toContain('Do not invent');

    const unknown = await bare.callTool(THOTH_PLACE_LOAD_TOOL, {
      city: 'Atlantis-Nowhere',
    });
    expect(unknown.result as string).toContain('could not load');

    const noPoi = makeClient({ observer: true, noPoi: true });
    const rec = await noPoi.callTool(THOTH_PLACE_RECOMMEND_TOOL, {
      kind: 'eat',
      hour: 12,
    });
    expect(rec.result as string).toContain('no named venues available');
    expect(rec.result as string).toContain('Do not invent places');
  });

  it('place.route plans multi-stop trips with distance/time/safety per leg', async () => {
    const client = makeClient({ observer: true });
    const trip = await client.callTool(THOTH_PLACE_ROUTE_TOOL, {
      stops: ['Luna Cafe', 'Main St Books'],
      roundTrip: true,
    });
    expect(trip.success).toBe(true);
    const text = trip.result as string;
    // Solver may be unavailable in stripped environments — both branches must
    // be honest. With the workspace WASM present we expect real legs.
    if (text.includes('routing solver unavailable')) {
      expect(text).toContain('Do not estimate');
    } else {
      expect(text).toContain('trip in Winters (round trip) — 2 legs:');
      expect(text).toMatch(/1\. Luna Cafe → Main St Books: [\d.]+km/);
      expect(text).toMatch(/2\. Main St Books → Luna Cafe: [\d.]+km/);
      expect(text).toMatch(/walk ~[\d.]+min/);
      expect(text).toContain('total ');
      expect(text).toContain('aeon-transportation');
      expect(text.split('\n').length).toBeLessThanOrEqual(13);
    }
  });

  it("place.route resolves 'here' via the observer and reports unknown stops", async () => {
    const client = makeClient({ observer: true });
    const trip = await client.callTool(THOTH_PLACE_ROUTE_TOOL, {
      stops: ['here', 'Valley Diner', 'Nonexistent Palace'],
    });
    const text = trip.result as string;
    expect(text).toContain(
      'unknown stops (not in the loaded city — do not invent them): Nonexistent Palace'
    );
    if (!text.includes('routing solver unavailable')) {
      expect(text).toMatch(/your location → Valley Diner/);
    }
    const tooFew = await client.callTool(THOTH_PLACE_ROUTE_TOOL, {
      stops: ['Luna Cafe'],
    });
    expect(tooFew.result as string).toContain('route needs at least 2 stops');
  });

  it('rejects unknown tool names like the oath client does', async () => {
    const client = makeClient();
    const res = await client.callTool('thoth/place.nope', {});
    expect(res.success).toBe(false);
    expect(res.error).toBe('Unknown Thoth place tool: thoth/place.nope');
  });

  it('every tool result stays inside the token-frugal envelope', async () => {
    const client = makeClient({ observer: true });
    const calls: Array<[string, Record<string, unknown>]> = [
      [THOTH_PLACE_LOAD_TOOL, { city: 'Winters' }],
      [THOTH_PLACE_SAMPLE_TOOL, { hour: 12 }],
      [THOTH_PLACE_SIMULATE_TOOL, { days: 7, limit: 10 }],
      [THOTH_PLACE_RECOMMEND_TOOL, { kind: 'visit', limit: 10 }],
      [THOTH_PLACE_QUERY_TOOL, { limit: 20 }],
    ];
    for (const [name, args] of calls) {
      const res = await client.callTool(name, args);
      expect(res.success).toBe(true);
      const text = res.result as string;
      expect(text.length).toBeLessThan(1200);
      expect(text.split('\n').length).toBeLessThanOrEqual(13);
    }
  });
});
